function DownloadIcon({ className }: { className?: string }) {
	return (
		<svg
			className={className}
			viewBox="0 0 24 24"
			fill="none"
			stroke="currentColor"
			strokeWidth="2"
			aria-hidden="true"
		>
			<path
				strokeLinecap="round"
				strokeLinejoin="round"
				d="M12 3v12m0 0l-4-4m4 4l4-4M3 17v2a2 2 0 002 2h14a2 2 0 002-2v-2"
			/>
		</svg>
	)
}

const platformIcons: Record<Platform, React.FC<{ className?: string }>> = {
	macos: AppleIcon,
	windows: WindowsIcon,
	linux: LinuxIcon,
}

interface PlatformCardProps {
	platform: Platform
	config: PlatformConfig
	release: ReleaseData | null
	isPrimary?: boolean
	detectedArch?: string
	index?: number
}

export function PlatformCard({
	platform,
	config,
	release,
	isPrimary = false,
	detectedArch,
	index = 0,
}: PlatformCardProps) {
	const [selectedArch, setSelectedArch] = useState<ArchitectureOption>(
		config.architectures.find((a) => a.id === detectedArch) ||
			config.architectures.find((a) => a.recommended) ||
			config.architectures[0],
	)

	const Icon = platformIcons[platform]
	const downloadUrl = getDownloadUrl(release, selectedArch)
	const hasRelease = release !== null && downloadUrl !== null

	return (
		<motion.div
			initial={{ opacity: 0, y: 20 }}
			animate={{ opacity: 1, y: 0 }}
			transition={{
				duration: 0.5,
				delay: isPrimary ? 0.2 : 0.4 + index * 0.1,
				ease: [0.23, 1, 0.32, 1],
			}}
			className={cn(
				"group relative flex flex-col items-center gap-4 p-6 rounded-xl",
				"border border-border bg-accent/50",
				"transition-all duration-300",
				"hover:border-secondary/50 hover:shadow-[0_0_30px_rgba(215,140,80,0.1)]",
				isPrimary && "md:col-span-3 md:flex-row md:justify-between md:p-8",
			)}
		>
			{/* Glow effect on hover */}
			<div
				className={cn(
					"pointer-events-none absolute inset-0 rounded-xl opacity-0 transition-opacity duration-300",
					"bg-gradient-to-b from-secondary/5 to-transparent",
					"group-hover:opacity-100",
				)}
			/>

			<div className={cn("flex items-center gap-4", isPrimary && "md:gap-6")}>
				<div
					className={cn(
						"flex items-center justify-center rounded-xl bg-secondary/10 p-3",
						"transition-transform duration-300 group-hover:scale-105",
						isPrimary && "p-4",
					)}
				>
					<Icon className={cn("size-8 text-secondary", isPrimary && "size-10")} />
				</div>

				<div className="flex flex-col">
					<h3 className={cn("font-semibold text-foreground", isPrimary ? "text-xl" : "text-lg")}>
						{config.name}
					</h3>
					<p className="text-sm text-muted-foreground">
						{hasRelease ? `v${release.version}` : "Coming Soon"}
					</p>
				</div>
			</div>

			<div
				className={cn(
					"flex w-full flex-col gap-3",
					isPrimary && "md:w-auto md:flex-row md:items-center",
				)}
			>
				{hasRelease && config.architectures.length > 1 && (
					<>
						<label htmlFor={`arch-select-${platform}`} className="sr-only">
							Select architecture for {config.name}
						</label>
						<select
							id={`arch-select-${platform}`}
							name="architecture"
							autoComplete="off"
							value={selectedArch.id}
							onChange={(e) => {
								const arch = config.architectures.find((a) => a.id === e.target.value)
								if (arch) setSelectedArch(arch)
							}}
							className={cn(
								"w-full rounded-lg border border-border bg-background px-3 py-2",
								"text-sm text-foreground",
								"focus:border-secondary focus:outline-none focus:ring-1 focus:ring-secondary",
								isPrimary && "md:w-48",
							)}
						>
							{config.architectures.map((arch) => (
								<option key={arch.id} value={arch.id}>
									{arch.label}
									{arch.recommended ? " (Recommended)" : ""}
								</option>
							))}
						</select>
					</>
				)}

				{hasRelease ? (
					<Button
						asChild
						variant="secondary"
						size={isPrimary ? "lg" : "default"}
						className="w-full md:w-auto"
					>
						<a href={downloadUrl} download className="gap-2">
							<DownloadIcon className="size-4" />
							Download
						</a>
					</Button>
				) : (
					<Button
						variant="secondary"
						size={isPrimary ? "lg" : "default"}
						disabled
						className="w-full md:w-auto opacity-60"
					>
						<DownloadIcon className="size-4" />
						Coming Soon
					</Button>
				)}
			</div>
		</motion.div>
	)
}
